const items = $input.all();

const customerId = $('Grab User').first().json.id;
const customerCode = $('On form submission').first().json["User Code"];

return items.map(item => {
  const j = item.json;

  return {
    json: {
      noteid: j.id ?? null,

      customerId: customerId ?? null,
      customerCode: customerCode ?? null,

      notes: j.notes ?? null,
      center_name: j.center?.name ?? null,
      added_by_name: j.added_by?.name ?? null,
      created_date: j.created_date ?? null,
      privacy_type: j.privacy_type ?? null
    }
  };
});

const output = {
  json: {
    fileCount: items.length
  },
  binary: {}
};

items.forEach((item, index) => {
  if (!item.binary) return;

  const keys = Object.keys(item.binary);
  if (keys.length === 0) return;

  const firstKey = keys[0];

  output.binary[`file${index + 1}`] = {
    ...item.binary[firstKey]
  };
});

return [output];

const items = $input.all();

function safeParseJson(str) {
  if (typeof str !== "string" || !str.trim()) return {};
  try {
    return JSON.parse(str);
  } catch (e) {
    return { __parseError: String(e?.message || e), __raw: str };
  }
}

function get(obj, path) {
  const parts = path.split(".");
  let cur = obj;
  for (const p of parts) {
    if (cur && Object.prototype.hasOwnProperty.call(cur, p)) cur = cur[p];
    else return undefined;
  }
  return cur;
}

// Try multiple paths, return first non-null/undefined
function pick(obj, paths, fallback = null) {
  for (const p of paths) {
    const v = get(obj, p);
    if (v !== undefined && v !== null) return v;
  }
  return fallback;
}

function cleanString(v) {
  if (typeof v !== "string") return v;
  // trims whitespace + removes trailing newlines etc.
  return v.replace(/\r?\n/g, " ").trim();
}

return items.map((item) => {
  const form = safeParseJson(item.json.data);

  return {
    json: {
      // optional wrapper/meta
      is_form_submitted: item.json.is_form_submitted ?? null,
      last_submitted_date_in_utc: item.json.last_submitted_date_in_utc ?? null,

      FirstName:      pick(form, ["textfieldzenGIFirstName"]),
      LastName:       pick(form, ["textfieldzenGILastName"]),
      AddressLineOne: cleanString(pick(form, ["textareazenGIAddressOne"])),
      AddressLineTwo: cleanString(pick(form, ["textareazenGIAddressTwo"])),
      City:           pick(form, ["textfieldzenGICity"]),
      PostalCode:     pick(form, ["textfieldzenGIPinCode"]),
      Country:        pick(form, ["selectzenGICountry"]),
      State:          pick(form, ["selectzenGIState"]),
      Email:          pick(form, ["emailzenGIEmail"]),

      MobilePhone:       pick(form, ["zenGIMobilePhone.phoneNumber"]),
      MobileCountryCode: pick(form, ["zenGIMobilePhone.countryCode"]),

      DateOfBirth: pick(form, ["datetimezenGIBirthday"]),
      Age:         pick(form, ["number"]),
      Gender:      pick(form, ["selectzenGIGender"]),

      // These two are stable in both samples
      PreviousSteps: pick(form, ["radio"]),
      HearAboutus:   pick(form, ["select"]),
      SignedDate:    pick(form, ["dateTime1"]),
      FormSubmitted: pick(form, ["btnFormioSubmit"]),

      // ---- MEDICAL YES/NO QUESTIONS ----
      // old numbering (radio2..radio14) vs new numbering (radio18..radio34)
      HeartDisease:   pick(form, ["radio2", "radio18"]),
      HighBlood:      pick(form, ["radio3", "radio19"]),
      LivKidProstate: pick(form, ["radio4", "radio20"]),
      Diabetes:       pick(form, ["radio5", "radio21"]),
      Thyriod:        pick(form, ["radio6", "radio22"]),
      AnemiaIron:     pick(form, ["radio7", "radio23"]),
      PyschiatricCon: pick(form, ["radio8", "radio24"]),

      // Skin conditions checkboxes moved from selectBoxes..selectBoxes8
      // to selectBoxes9..selectBoxes17
      Dermatitis:     pick(form, ["selectBoxes.dermatitis", "selectBoxes9.dermatitis"]),
      Psoriasis:      pick(form, ["selectBoxes1.psoriasis", "selectBoxes10.psoriasis"]),
      Eczema:         pick(form, ["selectBoxes2.eczema", "selectBoxes11.eczema"]),
      Dandruff:       pick(form, ["selectBoxes3.dandruff", "selectBoxes12.dandruff"]),
      ItchyScalp:     pick(form, ["selectBoxes4.itchyScalp", "selectBoxes13.itchyScalp"]),
      DryScalp:       pick(form, ["selectBoxes5.dryScalp", "selectBoxes14.dryScalp"]),
      OilyScalp:      pick(form, ["selectBoxes6.oilyScalp", "selectBoxes15.oilyScalp"]),
      HairLoss:       pick(form, ["selectBoxes7.hairLoss", "selectBoxes16.hairLoss"]),
      OtherCondition: pick(form, ["selectBoxes8.other", "selectBoxes17.other"]),

      // Remaining questions (old radio9..radio17) don’t exist in sample 2 the same way,
      // so we fallback to null unless you tell me the new mapping:
      RecEmoIllSur:     pick(form, ["radio9", "radio25"]),
      AttemptConceive:  pick(form, ["radio10", "radio26"]),
      OtherMedical:     pick(form, ["radio11", "radio27"]),
      MedicationIntake: pick(form, ["radio12", "radio28"]),
      SteriodTest:      pick(form, ["radio13", "radio29"]),
      AllericMedic:     pick(form, ["radio14", "radio30"]),
      SpecificDiet:     pick(form, ["radio15", "radio31"]),
      ConditionPresent: pick(form, ["radio16", "radio32"]),
      AgeRange:         pick(form, ["radio17", "radio33"]),

      Treatment:      cleanString(pick(form, ["textField4"])),
      MedicalHistory: cleanString(pick(form, ["textArea6", "textArea31"])), // NOTE: your sample 2 uses textArea31 for diet
      FamilyHistory:  cleanString(pick(form, ["textArea16", "textArea32"])), // sample 2 uses textArea32 for family
      ContentMacros:  pick(form, ["contentMacros"], {}),

      ParseError: pick(form, ["__parseError"], null),
    },
  };
});

return items.map(item => {
  let raw = item.json.data;

  // Step 1: Parse the main string
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    parsed = raw;
  }

  let output = {
    files: [],
    documents: []
  };

  // Case 1: First structure (file array)
  if (parsed?.file) {
    output.files = parsed.file.map(f => ({
      name: f.name,
      type: f.type,
      url: f.SihAccessUrl || f.presignedUrl,
      originalName: f.originalName
    }));
  }

  // Case 2: Second structure (imageURL-x list)
  if (Array.isArray(parsed)) {
    parsed.forEach(entry => {
      if (entry.value) {
        try {
          let val = JSON.parse(entry.value);
          output.documents.push({
            name: entry.name,
            url: val.sihAccessUrl || val.presignedUrl,
            originalUri: val.originalUri
          });
        } catch (e) {}
      }
    });
  }

  return {
    json: output
  };
});
